  args: {
    jsonSchema: {
      type: 'object',
      properties: {
        name: {
          type: 'string',
          title: 'Connection Name',
          minLength: 3,
          maxLength: 50
        },
        environment: {
          type: 'string',
          title: 'Environment',
          enum: ['production', 'staging', 'development'],
          default: 'development'
        },
        credentials: {
          type: 'object',
          title: 'Credentials',
          properties: {
            username: {
              type: 'string',
              title: 'Username'
            },
            password: {
              type: 'string',
              title: 'Password'
            }
          },
          required: ['username', 'password']
        },
        enableLogging: {
          type: 'boolean',
          title: 'Enable Request Logging',
          default: true
        },
        maxRetries: {
          type: 'integer',
          title: 'Max Retries',
          minimum: 0,
          maximum: 10,
          default: 3
        }
      },
      required: ['name', 'environment', 'credentials']
    },
    uiSchema: {
      type: 'VerticalLayout',
      elements: [{
        type: 'Control',
        scope: '#/properties/name'
      }, {
        type: 'Control',
        scope: '#/properties/environment'
      }, {
        type: 'Group',
        label: 'Authentication',
        elements: [{
          type: 'Control',
          scope: '#/properties/credentials/properties/username'
        }, {
          type: 'Control',
          scope: '#/properties/credentials/properties/password',
          options: {
            format: 'password'
          }
        }]
      }, {
        type: 'HorizontalLayout',
        elements: [{
          type: 'Control',
          scope: '#/properties/enableLogging'
        }, {
          type: 'Control',
          scope: '#/properties/maxRetries'
        }]
      }]
    }
  }
